-- Dumping data for table aah_db.services: ~12 rows (approximately)
INSERT INTO `services` (`id`, `sub_title`, `title`, `short_desc`, `sec_title`, `description`, `image`, `icon_image`, `created_at`, `updated_at`) VALUES
	(6, 'Boost Your Book Sales with Our Professional', 'Book Promotion', 'Our professional book promotion solutions meet your unique book marketing needs. We execute result-oriented book marketing strategies to make your book stand out.', 'ROI-Focused Book Marketing Solutions for Books of All Genres', '<p>Our team includes professional and experienced book marketers who join their heads together to create ingenious book marketing plans to get books featured on top media platforms. Our services are curated, with a special emphasis on bringing the most outstanding results in minimum time.</p>', 'services/book_promotion.png', 'services/icons/1762810000_icons8-promotion-100.png', '2025-11-10 21:26:40', '2026-07-22 16:20:06'),
	(7, 'Transform Your Book into An Audiobook with', 'Audio Book', 'Why sell a readable book only when you can get your story heard? Our team of experts at American Author Hub can transform your masterpiece into a stunning audio book.', 'Creating one-of-a-kind audiobooks that are too good to be true', '<p>Our team of audiobook publishers has collaborated with book writers and authors worldwide to create the best and most-streamed audiobooks, helping clients generate handsome revenue and make it to the list of best-selling audiobooks.</p>', 'services/audio_book.png', 'services/icons/1762881825_icons8-audio-book-100.png', '2025-11-11 17:23:45', '2026-07-22 16:20:07'),
	(8, 'We Offer Book Formatting Services That Meet All', 'Book Formatting', 'At American Author Hub, we understand that international book formatting standards can get in the way of your creative process resulting in a publishing dilemma. Our book editing and formatting services can solve these problems for you!', 'World-Class Book Formatting Services', '<p>Are you looking for professional book formatting services? At American Author Hub, our professional team helps you with self-publishing book formatting while ensuring that your book is publish-ready. Our formatting experts determine the precise formatting requirements based on your niche and audience, allowing you to concentrate on the writing work that matters the most while our team takes care of the rest.</p>', 'services/book_formatting.png', 'services/icons/1762882535_icons8-align-vertically-90.png', '2025-11-11 17:35:35', '2026-07-22 16:20:07'),
	(9, 'Ready To Publish Your Next eBook?', 'E-book Writing', 'Our team of professional eBook writers will assist you in becoming a best-seller author. If you\'re looking for a professional eBook writer for your book, we\'re here to help.', 'Catering To Your EBook Writing Services As Per International Standards', '<p>Looking for an experienced, reliable, and professional eBook writing company? Our seasoned professionals have extensive experience in E-Book writing as per the international standards and regulations. Get in touch with one of our experts to make your dream - of becoming a celebrated author - come true.</p>', 'services/ebook_writing.png', 'services/icons/1762883234_icons8-writing-80.png', '2025-11-11 17:47:14', '2026-07-22 16:20:07'),
	(10, 'Set Up An', 'Author Website', 'Do you want to make your name as an author? With a unique author website - that includes features to achieve larger visibility for you and your work - we will promote your story on your behalf throughout the world. We\'re here to assist you in achieving the spotlight you\'ve always desired.', 'We Make An Author Website For You And Assist You In Becoming The Bestseller!', '<p>Are you not getting the attention you deserve? Tell the readers who you truly are, using our author website builder services. You can be the next published author with the potential to achieve your desired marketing goals. Our skilled developers will create your Author\'s Website and promote your book on various platforms to engage readers from around the world.</p>', 'services/author_website.png', 'services/icons/1762883524_icons8-website-analytics-64.png', '2025-11-11 17:52:04', '2026-07-22 16:20:07'),
	(11, 'The Best Ghostwriting Company in Town', 'Ghostwriting', 'Our ghostwriters will create compelling content and bring your ideas to life to leave your readers mesmerized.', 'What we cover in Ghostwriting Services?', '<p>We are here to shape your readers\' perspectives. At American Auther Hub, you get to witness unmatched brilliance when our professional ghostwriters work their magic to bring your ideas to life. . Our professionals compose well-versed content that exhibits true professionalism while highlighting creativity. We are a bunch of inspiring ghostwriters who are dedicated to serving our clients to ensure their total satisfaction.</p>', 'services/ghostwriting.png', 'services/icons/1762885741_icons8-writing-100.png', '2025-11-11 18:29:02', '2026-07-22 16:20:07'),
	(12, 'Craft And Publish An Error-Free Book', 'Book Editing', 'No more truncated or lousy manuscripts! Hire American Auther Hub’s professional book editing services to perfect your manuscript and polish your rough idea into a masterpiece.', 'What do we cover in Book Editing?', '<p>Professional editing is required to transform a good book into a great one. We offer comprehensive editing services focusing on every minute detail while keeping an eye on the tone, flow, structure, and attention to detail.<br><br>With years of experience, Authors Time\'s team of professional book editors makes editing a breeze. They\'ll walk you through the revision process, make suggestions, and provide feedback.</p>', 'services/book_editing.jpg', 'services/icons/1762885995_icons8-video-editing-96.png', '2025-11-11 18:33:15', '2026-07-22 16:20:07'),
	(13, 'Make The Best First Impression on the Target', 'Book Cover', 'We can\'t judge a book by its cover, but the one with the best book cover design sells the most. Our design specialists at Authors Time know how to design an engaging book cover for your book, thereby helping you increase your book sales and generate revenues.', 'Attractive Book Cover Design Services with A High Return On Investment', '<p>Our team of expert designers at Authors Time understands how vital your book covers are in achieving the desired marketing results. You can trust our seasoned designers to deliver outstanding design ideas that are both excellent and relevant to the genre to which your work belongs.</p>', 'services/book_cover.jpg', 'services/icons/1762886194_icons8-wordbook-100.png', '2025-11-11 18:36:34', '2026-07-22 16:20:07'),
	(14, 'Make Your Audience Visualize What You\'re Talking', 'Book Video Trailer', 'Let\'s work together to produce the most appealing trailer for your book. The best technique to highlight your achievement is to show your masterpiece to the audience. Let\'s spark your audience\'s interest ahead of time.', 'Reading An Advertisement Can Be Boring', '<p>But a visual representation can capture attention in the first three seconds. You have just three seconds to sell a book and turn a visitor into your potential customer. Connect with us today to have your book&rsquo;s trailer designed by our creative team and let the audience experience the out-of-the-world representation of your book.</p>', 'services/book_video_trailer.jpg', 'services/icons/1762886413_icons8-video-trimming-100.png', '2025-11-11 18:40:13', '2026-07-22 16:20:07'),
	(15, 'Work with the Best Book Proofreading Company', 'Proofreading', 'Make your manuscript free from grammatical, spelling, clarity, and sentence structure issues. Our professional eBook proofreading services guarantee your manuscript\'s accuracy, consistency, and quality.', 'What’s Included in Our Book Proofreading Services?', '<p>Editing and proofreading are integral to a professional book writing and publishing service. With our experienced team of editors and proofreaders, we ensure that your manuscript is error-free before submitting it to the publisher. If your work is not properly edited and reviewed by specialists, the message you attempt to convey to the masses may be missed or diluted, regardless of how effectively you have authored the content. To ensure a flawless and error-free manuscript, have it read by experienced editors and proofreaders who are native English speakers with excellent knowledge of the subject matter of your book.</p>', 'services/proofreading.jpg', 'services/icons/1762887035_icons8-proofreading-96.png', '2025-11-11 18:50:35', '2026-07-22 16:20:07'),
	(16, 'Print Your Book with Confidence', 'Book Printing', 'High-Quality Book Printing Services: Get Your Book Professionally Printed', 'Get High-Quality Book Printing Services at Authors Time', '<p>American Auther Hub is dedicated to delivering top-notch book printing services that exceed your expectations. Our team of experienced book printers uses state-of-the-art printing technology to ensure that every book we print is of the highest quality. With our customizable book printing options, you can create a book representing your vision. And with our fast turnaround times and competitive pricing, you can trust us to deliver your books on time and within budget. Choose Authors Time for your next book printing project and experience the difference our high-quality services can make.</p>', 'services/book_printing.jpg', 'services/icons/1762887312_icons8-book-printing-64.png', '2025-11-11 18:55:12', '2026-07-22 16:20:07'),
	(17, 'Help You Get Your Work Seen', 'Publishing', 'Have you completed your masterpiece and are looking for a reputable publisher to publish it? We\'ve got you covered with our book publishing services to get your masterpiece out to the public.', 'Book Publishing Company – We’ve Published Hundreds Of Books Worldwide.', '<p>Do you struggle to reach out to your audience? No worries! Our team of publishing specialists and professionals can assist you in reaching your target audience by quickly getting your work published. Being a leading book publishing company, we have helped many writers to become celebrated authors of best-seller books.</p>', 'services/publishing.jpg', 'services/icons/1762887482_icons8-publishing-64.png', '2025-11-11 18:58:02', '2026-07-22 16:20:07');

